import React from 'react';
import '../WelcomeMessage.css';

class WelcomeMessage extends React.Component {
    constructor(props) {
      super(props);
      this.state = {
        currentPageName: props.currentPageName || 'Home'
      };
    }

    render() {
        return (
            <p>Welcome to everybody</p>
        );
    }
};

export default WelcomeMessage;
